const createNavItem = (component, name, to, icon) => ({
    component,
    name,
    to,
    icon: <CIcon icon={icon} customClassName="nav-icon" />,
});

const menuList = [
    createNavItem(CNavItem, "Dashboard", "/dashboard", cilBorderAll),
    createNavItem(CNavItem, "User Management", "/user-management", cilUser),
    createNavItem(CNavItem, "Course Management", "/course-management", cilSchool),
    createNavItem(CNavItem, "Content Management", "/content-management", cilSpreadsheet),
    createNavItem(CNavItem, "Magazine", "/magazine", cilSpreadsheet),
    createNavItem(CNavGroup, "Reports", "/base", cilCloudUpload),
    createNavItem(CNavItem, "Logout", "/logout", cilAccountLogout),
];

export default menuList;
